-- Seed data for signer_service (signer.db)
-- Table: sign_requests
-- Snapshot taken from local dev environment
PRAGMA journal_mode=WAL;

CREATE TABLE IF NOT EXISTS sign_requests (
    tx_id              TEXT PRIMARY KEY,
    auth_request_id    TEXT UNIQUE,
    user_id            TEXT NOT NULL,
    note               TEXT NOT NULL DEFAULT '',
    from_address       TEXT NOT NULL DEFAULT '',
    to_address         TEXT NOT NULL,
    value_wei          TEXT NOT NULL,
    data_hex           TEXT NOT NULL DEFAULT '0x',
    gas_limit          INTEGER NOT NULL DEFAULT 21000,
    chain              TEXT NOT NULL DEFAULT 'sepolia',
    status             TEXT NOT NULL DEFAULT 'pending_auth',
    signed_tx_hash     TEXT,
    raw_signed_tx      TEXT,
    error_reason       TEXT,
    created_at         TEXT NOT NULL,
    resolved_at        TEXT
);

